const body = $json.body ?? {};
const onlyDigits = (value) => String(value ?? '').replace(/\D/g, '');
const normalizeBrazilPhone = (value) => {
  const digits = onlyDigits(value);
  if (digits.length === 10 || digits.length === 11) return `55${digits}`;
  return digits;
};
const chatId = String(body.chat_id ?? body.from ?? body.customer_phone ?? '').replace(/\s+/g, '').trim();
const msg = String(body.text ?? body.message ?? '').replace(/\s+/g, ' ').trim();
return {
  tenant_id: body.tenant_id || null,
  tenant_phone_e164: normalizeBrazilPhone(body.tenant_phone_e164 ?? body.to ?? body.receiver ?? ''),
  customer_phone_e164: normalizeBrazilPhone(body.customer_phone_e164 ?? body.from ?? body.chat_id ?? ''),
  chat_id: chatId,
  msg,
  raw_body: body
};

const row = Array.isArray($json) ? $json[0] : $json;
const msg = String($node.Normalize.json.msg ?? '').trim();
const customerPhone = String($node.Normalize.json.customer_phone_e164 ?? '').trim();
const payload = row.payload_draft ?? {};
const draft = payload.appointment ?? {};
const services = Array.isArray(row.services) ? row.services : [];
const staff = Array.isArray(row.staff_members) ? row.staff_members : [];
const step = row.step || 'appointment_welcome';
const tenantName = row.tenant_name || 'nossa equipe';

function reply(text, nextStep, patch = {}, close = false) {
  return [{ json: {
    action: 'patch',
    reply: text,
    conversation_id: row.conversation_id,
    next_step: nextStep,
    p_close: close,
    data_patch: {
      appointment: {
        ...patch,
        customer_whatsapp: customerPhone || draft.customer_whatsapp || null
      },
      metadata: { last_step: nextStep, updated_at: new Date().toISOString() }
    }
  }}];
}

function createAppointment() {
  const service = services.find((item) => item.id === draft.service_id) ?? null;
  const staffMember = staff.find((item) => item.id === draft.staff_member_id) ?? null;
  return [{ json: {
    action: 'create',
    conversation_id: row.conversation_id,
    next_step: 'appointment_done',
    p_close: true,
    create_body: {
      p_tenant_id: row.tenant_id,
      p_full_name: draft.full_name,
      p_cpf: draft.cpf,
      p_whatsapp_e164: customerPhone || draft.customer_whatsapp,
      p_birth_date: draft.birth_date,
      p_service_id: draft.service_id || null,
      p_staff_member_id: draft.staff_member_id || null,
      p_starts_at: draft.starts_at,
      p_ends_at: draft.ends_at,
      p_title: service ? service.name : 'Agendamento via WhatsApp',
      p_notes: `Criado via WhatsApp${staffMember ? ' com ' + staffMember.name : ''}.`
    }
  }}];
}

function parseCpf(value) {
  const cpf = String(value ?? '').replace(/\D/g, '');
  if (cpf.length !== 11 || /^(\d)\1{10}$/.test(cpf)) return null;
  return cpf;
}

function parseDateBR(value) {
  const match = String(value ?? '').trim().match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (!match) return null;
  const day = match[1].padStart(2, '0');
  const month = match[2].padStart(2, '0');
  const year = match[3];
  const iso = `${year}-${month}-${day}`;
  const date = new Date(`${iso}T00:00:00-03:00`);
  if (Number.isNaN(date.getTime())) return null;
  return iso;
}

function parseTime(value) {
  const match = String(value ?? '').trim().match(/^(\d{1,2})[:hH](\d{2})$/);
  if (!match) return null;
  const hour = Number(match[1]);
  const minute = Number(match[2]);
  if (hour < 0 || hour > 23 || minute < 0 || minute > 59) return null;
  return `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
}

function renderServiceMenu() {
  if (!services.length) return 'Ainda nao ha servicos cadastrados para este tenant. Fale com a equipe para configurar a agenda.';
  return 'Escolha o servico:\n' + services.map((service, index) => `${index + 1}) ${service.name}${service.duration_minutes ? ' - ' + service.duration_minutes + 'min' : ''}`).join('\n');
}

function renderStaffMenu() {
  if (!staff.length) return 'Nao ha profissionais cadastrados. Vou seguir sem profissional especifico. Envie *ok* para continuar.';
  return 'Escolha o profissional:\n' + staff.map((member, index) => `${index + 1}) ${member.name}`).join('\n') + '\n\nEnvie 0 para sem preferencia.';
}

if (!msg && step !== 'appointment_welcome') {
  return reply('Nao recebi nenhuma mensagem. Pode enviar novamente?', step, draft);
}

if (['menu', '0', 'inicio', 'iniciar'].includes(msg.toLowerCase()) || step === 'appointment_welcome') {
  const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
  return reply(`${welcome}\n\nPara comecar, me informe seu nome completo.`, 'collect_full_name', {});
}

if (step === 'collect_full_name') {
  const name = msg.replace(/\s+/g, ' ').trim();
  if (name.split(' ').filter(Boolean).length < 2) return reply('Me informe seu nome completo, por favor. Ex: Joao Silva.', step, draft);
  return reply('Perfeito. Agora envie seu CPF com 11 digitos.', 'collect_cpf', { ...draft, full_name: name });
}

if (step === 'collect_cpf') {
  const cpf = parseCpf(msg);
  if (!cpf) return reply('CPF invalido. Envie apenas os 11 digitos.', step, draft);
  return reply('Agora envie sua data de nascimento no formato DD/MM/AAAA.', 'collect_birth_date', { ...draft, cpf });
}

if (step === 'collect_birth_date') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data invalida. Envie no formato DD/MM/AAAA.', step, draft);
  return reply(renderServiceMenu(), 'choose_service', { ...draft, birth_date: birthDate });
}

if (step === 'choose_service') {
  if (!services.length) return reply(renderServiceMenu(), step, draft);
  const selected = services[Number(msg) - 1];
  if (!selected) return reply(renderServiceMenu(), step, draft);
  return reply(renderStaffMenu(), 'choose_staff', { ...draft, service_id: selected.id, service_name: selected.name, duration_minutes: selected.duration_minutes || 60 });
}

if (step === 'choose_staff') {
  let selected = null;
  if (msg !== '0' && msg.toLowerCase() !== 'ok') {
    selected = staff[Number(msg) - 1];
    if (!selected) return reply(renderStaffMenu(), step, draft);
  }
  return reply('Qual dia voce deseja agendar? Envie no formato DD/MM/AAAA.', 'collect_date', { ...draft, staff_member_id: selected?.id ?? null, staff_member_name: selected?.name ?? null });
}

if (step === 'collect_date') {
  const date = parseDateBR(msg);
  if (!date) return reply('Data invalida. Envie no formato DD/MM/AAAA.', step, draft);
  return reply('Qual horario? Envie no formato HH:MM, por exemplo 14:30.', 'collect_time', { ...draft, appointment_date: date });
}

if (step === 'collect_time') {
  const time = parseTime(msg);
  if (!time) return reply('Horario invalido. Envie no formato HH:MM, por exemplo 14:30.', step, draft);
  const duration = Number(draft.duration_minutes || 60);
  const startsAt = `${draft.appointment_date}T${time}:00-03:00`;
  const ends = new Date(new Date(startsAt).getTime() + duration * 60 * 1000);
  const endsAt = ends.toISOString();
  const summary = `Confirme seu agendamento:\n\nNome: ${draft.full_name}\nServico: ${draft.service_name || '-'}\nProfissional: ${draft.staff_member_name || 'Sem preferencia'}\nData: ${draft.appointment_date}\nHorario: ${time}\n\nResponda *sim* para confirmar ou *0* para recomecar.`;
  return reply(summary, 'confirm_appointment', { ...draft, appointment_time: time, starts_at: startsAt, ends_at: endsAt });
}

if (step === 'confirm_appointment') {
  if (!['sim', 's', 'confirmar', 'confirmo'].includes(msg.toLowerCase())) {
    return reply('Tudo bem. Envie 0 para recomecar ou responda *sim* para confirmar os dados acima.', step, draft);
  }
  return createAppointment();
}

return reply('Vamos recomecar. Me informe seu nome completo.', 'collect_full_name', {});

return [{ json: {
  reply: 'Agendamento confirmado! Em breve a equipe pode falar com voce por aqui se precisar ajustar algo.',
  conversation_id: $node.FN_appointment_state_machine.json.conversation_id,
  next_step: 'appointment_done',
  p_close: true,
  data_patch: {
    appointment: {
      appointment_id: Array.isArray($json) ? $json[0] : $json
    },
    metadata: {
      completed_at: new Date().toISOString()
    }
  }
}}];
